import{_ as e}from"./chunks/demo-doc.D32o-ZLW.js";import{c as r,Q as d,j as t,m as a}from"./chunks/framework.BkjtU8k0.js";const v=JSON.parse('{"title":"概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/overview.md","filePath":"guide/overview.md","lastUpdated":1779097958000}'),i={name:"guide/overview.md"};function s(c,o,l,n,p,h){return d(),t("div",null,[...o[0]||(o[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>Flyfish Viewer 可以为您的应用快速集成文档预览能力。不同于市面上的文档预览方案，本项目对文档的所有解析和渲染全部都在浏览器端完成，不会给服务器造成任何额外的压力。与此同时，因其纯前端的特性，非常易于部署，可以部署在任何地方，如容器、服务器、甚至是手机、路由器等等。</p><p>查看<a href="/guide/quickstart">快速开始</a>了解详情。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h2><ul><li>📄 <strong>支持海量文件格式。</strong> 支持 <code>docx</code>、<code>pptx</code>、<code>xlsx</code>、<code>xls</code>、<code>pdf</code>、<code>ofd</code>、<code>dxf</code>、<code>markdown</code>、代码高亮、图片、视频等主流文件格式。</li><li>🌐 <strong>现代纯前端文档渲染方案。</strong> 纯前端文档预览解决方案，无需后端。</li><li>🛠 <strong>优质代码，优雅实现。</strong> 高质量的 TypeScript 代码，优雅的模块化实现。</li><li>🚀 <strong>持续使用最新架构。</strong> 基于最新 <strong>Vite</strong> 开发，并同时支持 <strong>Vue2</strong> 和 <strong>Vue3</strong>。</li><li>⚡ <strong>异步渲染和解析。</strong> 所有文件解析使用 <strong>Web Worker</strong> 异步处理，请纵享丝滑。</li><li>🧩 <strong>完全响应式数据构建。</strong> 使用完全的组合式 API 构建应用，高性能低占用。</li><li>🎨 <strong>支持完全的样式自定义。</strong> 解耦样式依赖，组件样式可以根据外部容器完全自适应。</li><li>🔌 <strong>更加灵活的扩展性。</strong> 支持自定义插件和钩子函数。</li><li>🎉 <strong>成品开放，持续更新</strong> 🎉🎉🎉</li></ul><h2 id="当前版本补充说明" tabindex="-1">当前版本补充说明 <a class="header-anchor" href="#当前版本补充说明" aria-label="Permalink to &quot;当前版本补充说明&quot;">​</a></h2><div class="doc-grid"><div class="doc-card"><h3>`.doc` 体验持续优化</h3><p>当前版本对 `.doc` 文件使用 `msdoc-viewer` 进行解析，并在渲染层额外套用 Word 风格页面容器。</p></div><div class="doc-card"><h3>OFD 与 CAD 入列</h3><p>新增 `DLTech21/ofd.js` 源码在线预览和 DXF 图纸预览，OFD 避开 npm dist 授权 wasm 分支，重型依赖保持异步加载。</p></div><div class="doc-card"><h3>代码高亮预览</h3><p>代码和日志文件使用 `highlight.js` 轻量高亮，HTML 仍按源码展示，不在预览器中执行。</p></div><div class="doc-card"><h3>PDF 阅读体验升级</h3><p>PDF 已补齐缩放工具栏、页码状态和可显隐导航窗格，长文档阅读更顺手。</p></div><div class="doc-card"><h3>适合业务交付</h3><p>除了功能本身，文档、Demo、混淆压缩、npm 打包和静态部署链路也已经一并完善，适合直接用于成品分发和项目接入。</p></div></div><h2 id="成品与源码" tabindex="-1">成品与源码 <a class="header-anchor" href="#成品与源码" aria-label="Permalink to &quot;成品与源码&quot;">​</a></h2><p>公开 GitHub 仓库用于分发可直接下载使用的构建产物和示例，不包含源码目录。需要源码、二开包或商业自助开通的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><p>项目遵循 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code>。</p><div class="doc-shot"><img src="'+e+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">`.doc` 页面已经按 Word 风格居中显示在灰色工作台中，这一层体验补足了原有纯内容渲染的阅读落差。</p></div>',11)])])}const u=r(i,[["render",s]]);export{v as __pageData,u as default};
